// Importing ethers library
const ethers = require('ethers');

// Provider for mainnet
let provider = ethers.getDefaultProvider('homestead');

// ERC20 Token and DEX smart contract addresses
let ERC20TokenAddress = 'YOUR_ERC20_TOKEN_ADDRESS';
let DEXAddress = 'YOUR_DEX_SMART_CONTRACT_ADDRESS';

// ERC20 Standard ABI
let ERC20ABI = [
    // Some details about the token
    "function name() view returns (string)",
    "function symbol() view returns (string)",

    // Get the account balance
    "function balanceOf(address) view returns (uint)",

    // Send some of your tokens to someone else
    "function transfer(address to, uint amount)",

    // Allow someone else to spend up to a certain number of tokens
    "function approve(address spender, uint amount)"
];

// ABI of DEX contract
let DEXABI = [
    // Swap function
    "function swap(address fromToken, address toToken, uint amount)"
];

// Creating instances of contracts
let signer = new ethers.Wallet('YOUR_WALLET_PRIVATE_KEY', provider);
let ERC20Contract = new ethers.Contract(ERC20TokenAddress, ERC20ABI, signer);
let DEXContract = new ethers.Contract(DEXAddress, DEXABI, signer);

// Approve maximum uint256 amount
let MAX_INT = ethers.constants.MaxUint256;
ERC20Contract.approve(DEXAddress, MAX_INT);

// Swap example
async function swap(amount){
    try {
        let result = await DEXContract.swap(ERC20TokenAddress, 'ADDRESS_OF_TOKEN_TO_SWAP', amount);
        console.log('Swap Executed: ', result);
    } catch (error) {
        console.log('Error during Swap: ', error);
    }
}

swap(1000); // Change this number to desired amount